import hashlib
import json
from collections import defaultdict
from typing import Any, Callable

class ToolLoopGuard:
    def __init__(self, max_identical_calls: int = 3, max_total_calls: int = 50):
        self.max_identical_calls = max_identical_calls
        self.max_total_calls = max_total_calls
        self._call_counts: dict[str, int] = defaultdict(int)
        self._total_calls: int = 0

    def _fingerprint(self, tool_name: str, args: dict) -> str:
        payload = json.dumps({"tool": tool_name, "args": args}, sort_keys=True)
        return hashlib.sha256(payload.encode()).hexdigest()

    def check(self, tool_name: str, args: dict) -> None:
        self._total_calls += 1
        if self._total_calls > self.max_total_calls:
            raise RuntimeError(
                f"Tool call budget exceeded ({self.max_total_calls} calls). "
                "Task may be stuck in a loop. Aborting."
            )
        fp = self._fingerprint(tool_name, args)
        self._call_counts[fp] += 1
        if self._call_counts[fp] > self.max_identical_calls:
            raise RuntimeError(
                f"Tool loop detected: '{tool_name}' called with identical "
                f"arguments {self._call_counts[fp]} times. "
                "Breaking loop to prevent runaway execution."
            )

    def wrap(self, tool_fn: Callable) -> Callable:
        def guarded(*args, **kwargs):
            tool_name = tool_fn.__name__
            self.check(tool_name, kwargs)
            return tool_fn(*args, **kwargs)
        return guarded

# Usage
