from collections import deque
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class ToolCallRecord:
    tool_name: str
    args_summary: str
    result_summary: str

class LoopAwareContextBuilder:
    def __init__(self, history_window: int = 10):
        self.history: deque[ToolCallRecord] = deque(maxlen=history_window)

    def record(self, tool_name: str, args: dict, result: str) -> None:
        self.history.append(ToolCallRecord(
            tool_name=tool_name,
            args_summary=str(args)[:120],
            result_summary=result[:200]
        ))

    def build_history_prompt(self) -> str:
        if not self.history:
            return ""
        lines = ["## Recent Tool Call History (avoid repeating these):\n"]
        for i, record in enumerate(self.history, 1):
            lines.append(
                f"{i}. Tool: {record.tool_name} | "
                f"Args: {record.args_summary} | "
                f"Result: {record.result_summary}"
            )
        lines.append(
            "\nIf your next action is identical or semantically similar to "
            "a recent call above, choose a different approach instead.\n"
        )
        return "\n".join(lines)

    def augment_messages(self, messages: list[dict]) -> list[dict]:
        history_prompt = self.build_history_prompt()
        if not history_prompt:
            return messages
        # Inject as a system message before the last user message
        augmented = list(messages)
        augmented.insert(-1, {"role": "system", "content": history_prompt})
        return augmented

