from enum import Enum
from typing import Optional

class LoopSeverity(Enum):
    WARNING = 1
    INTERVENTION = 2
    ABORT = 3

class GradualLoopIntervenor:
    MESSAGES = {
        LoopSeverity.WARNING: (
            "[SYSTEM NOTICE] You have called '{tool}' with similar arguments "
            "{count} time(s). Consider whether this approach is working."
        ),
        LoopSeverity.INTERVENTION: (
            "[SYSTEM INTERVENTION] You have called '{tool}' {count} time(s) "
            "without progress. You MUST try a fundamentally different approach. "
            "Do not call '{tool}' again until you have attempted at least one "
            "other strategy."
        ),
        LoopSeverity.ABORT: (
            "[SYSTEM ABORT] Repeated tool loop detected for '{tool}' ({count} calls). "
            "Task cannot be completed with the current strategy. "
            "Returning partial results and escalating to human review."
        ),
    }

    def __init__(self, warn_at: int = 2, intervene_at: int = 4, abort_at: int = 6):
        self.thresholds = {
            LoopSeverity.WARNING: warn_at,
            LoopSeverity.INTERVENTION: intervene_at,
            LoopSeverity.ABORT: abort_at,
        }
        self._counts: dict[str, int] = {}

    def evaluate(self, tool_name: str) -> Optional[tuple[LoopSeverity, str]]:
        self._counts[tool_name] = self._counts.get(tool_name, 0) + 1
        count = self._counts[tool_name]
        for severity in reversed(list(LoopSeverity)):
            if count >= self.thresholds[severity]:
                msg = self.MESSAGES[severity].format(tool=tool_name, count=count)
                return severity, msg
        return None

    def should_abort(self, tool_name: str) -> bool:
        count = self._counts.get(tool_name, 0)
        return count >= self.thresholds[LoopSeverity.ABORT]

# Usage
